def mocker_s(repo_is_ee, syslog_mock, extra_lo_ips, dns_server_mock_s):
    """Provide a gc-ed mocker instance suitable for the repository flavour"""
    if repo_is_ee:
        from mocker.ee import Mocker
    else:
        from mocker.open import Mocker

    m = Mocker()
    m.start()

    yield m

    m.stop()

